-- ============================================================
-- TABLE 11: ref_hsd_required_counts
-- PURPOSE: EXACT REQUIRED PROVIDER/FACILITY COUNTS PER COUNTY
--          PER CMS 2026 HSD REFERENCE FILE
-- SOURCE:  CMS 2026 HSD Reference File (12-17-2025)
--          https://www.cms.gov/medicare/health-drug-plans/medicare-advantage-application
-- GRAIN:   county_name x cms_specialty
-- NOTE:    REPLACES APPROXIMATED required_provider_count IN fact_gap_analysis
--          USE THIS TABLE INSTEAD OF RATIO CALCULATION
-- ============================================================

CREATE OR REPLACE TABLE `anbc-hcb-dev.provider_ds_netconf_data_hcb_dev.A870800_medicare_supply_demand_ref_hsd_required_counts`
OPTIONS (labels=[("owner", "deepan_thulasi_aetna_com")])
